<template><view @click="visible = true"><wd-search :placeholder="placeholder" hide-cancel disabled /></view><wd-popup v-model="visible" position="top" :custom-style="getTopPopupStyle()" :modal-style="getTopPopupModalStyle()" @close="visible = false"><view class="yd-search-form-container"><view class="yd-search-form-item"><view class="yd-search-form-label">任务名称</view><wd-input v-model="formData.name" placeholder="请输入任务名称" clearable /></view><view class="yd-search-form-item"><view class="yd-search-form-label">任务状态</view><wd-radio-group v-model="formData.status" type="button"><wd-radio :value="-1">全部</wd-radio><wd-radio v-for="dict in getIntDictOptions(DICT_TYPE.IOT_OTA_TASK_STATUS)" :key="dict.value" :value="dict.value">{{ dict.label }}</wd-radio></wd-radio-group></view><view class="yd-search-form-actions"><wd-button class="flex-1" variant="plain" @click="handleReset">重置</wd-button><wd-button class="flex-1" type="primary" @click="handleSearch">搜索</wd-button></view></view></wd-popup></template><script lang="ts" setup>import { computed, reactive, ref } from 'vue'; import { getIntDictOptions } from '@/hooks/useDict'; import { getTopPopupModalStyle, getTopPopupStyle } from '@/utils'; import { DICT_TYPE } from '@/utils/constants'; const emit = defineEmits<{ search: [data: Record<string, any>], reset: [] }>(); const visible = ref(false); const formData = reactive({ name: undefined as string | undefined, status: -1 }); const placeholder = computed(() => formData.name ? '任务名称:' + formData.name : '搜索升级任务'); function handleSearch() { visible.value = false; emit('search', { name: formData.name, status: formData.status === -1 ? undefined : formData.status }) } function handleReset() { formData.name = undefined; formData.status = -1; visible.value = false; emit('reset') }</script>